var comfyuiUrl = null;

try {
  var pods = response.data.myself.pods || [];
  for (var p of pods) {
    if (p.name === 'clay-comfyui' && p.desiredStatus === 'RUNNING') {
      var uptime = p.runtime ? p.runtime.uptimeInSeconds : 0;
      if (uptime > 30) {
        podEncontrado = true;
        podId = p.id;
        comfyuiUrl = 'https://' + p.id + '-8188.proxy.runpod.net';
        break;
      }
    }
  }
} catch(e) {}

if (podEncontrado) {
  staticData.podId = podId;
  staticData.comfyuiUrl = comfyuiUrl;
}

return [{ json: { _podExiste: podEncontrado, podId: podId, comfyuiUrl: comfyuiUrl } }];

