var promptId = staticData.audioPromptId;
staticData.audioRetries = (staticData.audioRetries || 0) + 1;
var pronto = false; var filename = null; var erro = false; var erroMsg = '';
try {
  var hist = input[promptId];
  if (hist) {
    var statusStr = hist.status ? hist.status.status_str : null;
    if (statusStr === 'error') {
      erro = true;
      var msgs = hist.status.messages || [];
      for (var m of msgs) { if (m[0] === 'execution_error') { erroMsg = m[1].exception_message || 'Erro desconhecido'; break; } }
    } else if (hist.outputs) {
      var keys = Object.keys(hist.outputs);
      for (var k = 0; k < keys.length; k++) {
        var nodeOut = hist.outputs[keys[k]];
        if (nodeOut.audio && nodeOut.audio.length > 0) { filename = nodeOut.audio[0].filename; pronto = true; break; }
      }
    }
  }
} catch(e) {}
var meta = $('Preparar Polling Audio').first().json;
return [{ json: { _ready: pronto, _error: erro, _errorMsg: erroMsg, _timeout: (!pronto && !erro && staticData.audioRetries >= 60), filename: filename, downloadUrl: pronto ? (staticData.comfyuiUrl + '/view?filename=' + encodeURIComponent(filename) + '&type=output') : null, cenaId: meta.cenaId, cenaNumero: meta.cenaNumero, videoId: meta.videoId, emocao: meta.emocao } }];

var msg = $('Avaliar Resultado').first().json._errorMsg || 'Erro desconhecido';
var meta = $('Avaliar Resultado').first().json;
throw new Error('❌ TTS ERRO na cena ' + meta.cenaNumero + ': ' + msg);

const meta = $input.first().json;
const config = $('Configuração').first().json;
const storagePath = meta.videoId + '/narr_' + meta.cenaNumero + '.mp3';
const publicUrl = config.SUPABASE_URL + '/storage/v1/object/public/narracoes/' + storagePath;
return [{ json: { downloadUrl: meta.downloadUrl, uploadUrl: config.SUPABASE_URL + '/storage/v1/object/narracoes/' + storagePath, publicUrl: publicUrl, cenaId: meta.cenaId, cenaNumero: meta.cenaNumero, videoId: meta.videoId, supabaseKey: config.SUPABASE_SERVICE_KEY } }];

const meta = $('Prep Download').first().json;

// Download via httpRequest helper (segue redirects)
const response = await this.helpers.httpRequest({
  method: 'GET',
  url: meta.downloadUrl,
  encoding: 'arraybuffer',
  returnFullResponse: true,
});

const buffer = Buffer.from(response.body);

let duration = 0;
try {
  const brV1L3 = [0,32,40,48,56,64,80,96,112,128,160,192,224,256,320,0];
  const brV2L3 = [0,8,16,24,32,40,48,56,64,80,96,112,128,144,160,0];
  const srV1 = [44100,48000,32000];
  const srV2 = [22050,24000,16000];
  let frameCount = 0; let sampleRate = 24000; let samplesPerFrame = 576; let pos = 0;
  while (pos < buffer.length - 4) {
    if (buffer[pos] === 0xFF && (buffer[pos + 1] & 0xE0) === 0xE0) {
      const header = buffer.readUInt32BE(pos);
      const mpegVer = (header >> 19) & 3;
      const brIdx = (header >> 12) & 15;
      const srIdx = (header >> 10) & 3;
      const padding = (header >> 9) & 1;
      let br, sr, spf, frameLen;
      if (mpegVer === 3) { br = brV1L3[brIdx]*1000; sr = srIdx<3?srV1[srIdx]:44100; spf=1152; frameLen=br>0?Math.floor((144*br)/sr)+padding:0; }
      else { br = brV2L3[brIdx]*1000; sr = srIdx<3?srV2[srIdx]:24000; spf=576; frameLen=br>0?Math.floor((72*br)/sr)+padding:0; }
      if (frameLen > 0) { frameCount++; sampleRate=sr; samplesPerFrame=spf; pos+=frameLen; } else { pos++; }
    } else { pos++; }
  }
  if (frameCount > 0 && sampleRate > 0) { duration = (frameCount * samplesPerFrame) / sampleRate; }
} catch(e) {}

duration = Math.round(duration * 100) / 100;

// Passar binary para upload
const binaryData = await this.helpers.prepareBinaryData(buffer, 'audio.mp3', 'audio/mpeg');

return [{ json: { duracao_real: duration }, binary: { data: binaryData } }];

var staticData = $getWorkflowStaticData('global');
var podId = staticData.podId || '';
return [{ json: { stopBody: { query: 'mutation { podTerminate(input: {podId: "' + podId + '"}) }' } } }];
